class Solution {
public:
    vector<int> powerfulIntegers(int x, int y, int bound) {
        vector<int> a_list;
        int a = 1;
        while (a <= bound - 1) {
            a_list.push_back(a);
            if (x == 1) break;
            a *= x;
        }

        vector<int> b_list;
        int b = 1;
        while (b <= bound - 1) {
            b_list.push_back(b);
            if (y == 1) break;
            b *= y;
        }

        set<int> result_set;

        for (auto ai : a_list) {
            for (auto bj : b_list) {
                int sum = ai + bj;
                if (sum <= bound) {
                    result_set.insert(sum);
                }
            }
        }

        return vector<int>(result_set.begin(), result_set.end());
    }
};

